import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import LoginPage from './pages/LoginPage';
import Dashboard from './pages/Dashboard';
import UserListPage from './pages/UserListPage';
import CustomerListPage from './pages/CustomerListPage';
import KhaiBaoCoSo from './pages/KhaiBaoCoSo';
import LogoutPage from './pages/LogoutPage';
import Sidebar from './components/Sidebar'; // Đảm bảo đường dẫn này đúng
import FarmDetail from './pages/FarmDetail';
import FarmListPage from './pages/FarmListPage'; // Đảm bảo import FarmListPage

function App() {
  const token = localStorage.getItem('token');
  const role = localStorage.getItem('role');

  return (
    <Router>
      {/* Đây là container chính của toàn bộ layout. */}
      {/* Nó sẽ có display: flex để Sidebar và phần nội dung chính nằm cạnh nhau. */}
      <div className="dashboard-layout"> {/* Áp dụng class CSS cho layout tổng thể */}
        {token && <Sidebar />} {/* Sidebar chỉ hiển thị nếu có token (người dùng đã đăng nhập) */}

        {/* Đây là div chứa nội dung chính của trang (Dashboard, KhaiBaoCoSo, v.v.). */}
        {/* Nó sẽ co giãn để chiếm hết không gian còn lại. */}
        <div className="main-content-wrapper"> {/* Áp dụng class CSS cho phần nội dung chính */}
          <Routes>
            <Route path="/" element={<LoginPage />} />
            <Route path="/dashboard" element={token ? <Dashboard /> : <Navigate to="/" />} />
            <Route path="/khai-bao" element={token ? <KhaiBaoCoSo /> : <Navigate to="/" />} />
            <Route path="/admin/farms" element={token && role === 'admin' ? <FarmListPage /> : <Navigate to="/" />} />
            <Route path="/farm-details/:farmId" element={token ? <FarmDetail /> : <Navigate to="/" />} />
            <Route path="/admin/users" element={token && role === 'admin' ? <UserListPage /> : <Navigate to="/" />} />
            <Route path="/admin/customers" element={token && role === 'admin' ? <CustomerListPage /> : <Navigate to="/" />} />
            <Route path="/logout" element={<LogoutPage />} />
          </Routes>
        </div>
      </div>
    </Router>
  );
}

export default App;
